import type { RecordId } from "surrealdb";

export type DescriptionEntry = {
  text: string;
  reasoning: string;
  triggered_by: RecordId[];
  created_at: Date;
};

export type DescriptionTarget = "project" | "feature" | "task";

export type DescriptionTriggerKind =
  | "decision_confirmed"
  | "feature_created"
  | "feature_completed"
  | "task_completed"
  | "task_created"
  | "scope_changed";

export type DescriptionTrigger = {
  kind: DescriptionTriggerKind;
  entity: RecordId;
  summary: string;
};
import { generateObject } from "ai";
import { z } from "zod";
import type { DescriptionEntry, DescriptionTarget } from "./types";

const synthesisOutputSchema = z.object({
  description: z.string().min(1),
});

export async function synthesizeDescription(input: {
  extractionModel: any;
  entityName: string;
  entityType: DescriptionTarget;
  entries: DescriptionEntry[];
}): Promise<string> {
  const entryLines = input.entries
    .map((entry, i) => `${i + 1}. ${entry.text} (${entry.reasoning})`)
    .join("\n");

  const result = await generateObject({
    model: input.extractionModel,
    schema: synthesisOutputSchema,
    temperature: 0.1,
    system: [
      "You synthesize entity descriptions from a list of description entries.",
      "Each entry represents a fact or change about the entity.",
      "Produce a single coherent description paragraph that incorporates all entries.",
      "Keep it concise: 1-4 sentences depending on how many entries there are.",
      "If entries contradict each other, prefer the latest (highest numbered) entry.",
      "Do not include entry numbers, reasoning, or metadata in the output.",
    ].join(" "),
    prompt: [
      `Entity type: ${input.entityType}`,
      `Entity name: ${input.entityName}`,
      "",
      "Description entries:",
      entryLines,
    ].join("\n"),
  });

  return (result.object as { description: string }).description;
}
import type { RecordId, Surreal } from "surrealdb";
import { logError, logInfo } from "../http/observability";
import { synthesizeDescription } from "./generate";
import type { DescriptionEntry, DescriptionTarget } from "./types";

type EntityWithDescriptionEntries = {
  name?: string;
  title?: string;
  description_entries?: DescriptionEntry[];
};

function resolveEntityName(row: EntityWithDescriptionEntries): string {
  return row.name ?? row.title ?? "Unknown";
}

export async function appendDescriptionEntry(input: {
  surreal: Surreal;
  extractionModel: any;
  targetRecord: RecordId;
  targetType: DescriptionTarget;
  entry: DescriptionEntry;
}): Promise<void> {
  const [rows] = await input.surreal
    .query<[EntityWithDescriptionEntries[]]>(
      "SELECT name, title, description_entries FROM $record LIMIT 1;",
      { record: input.targetRecord },
    )
    .collect<[EntityWithDescriptionEntries[]]>();

  const existing = rows[0];
  if (!existing) {
    logError("description.append.entity_not_found", "Target entity not found", undefined, {
      targetRecord: `${input.targetRecord.table}:${input.targetRecord.id}`,
    });
    return;
  }

  const entries = [...(existing.description_entries ?? []), input.entry];
  const entityName = resolveEntityName(existing);

  let description: string;
  if (entries.length === 1) {
    description = input.entry.text;
  } else {
    description = await synthesizeDescription({
      extractionModel: input.extractionModel,
      entityName,
      entityType: input.targetType,
      entries,
    });
  }

  await input.surreal.update(input.targetRecord).merge({
    description,
    description_entries: entries,
    updated_at: new Date(),
  });

  logInfo("description.append.success", "Description entry appended", {
    targetRecord: `${input.targetRecord.table}:${input.targetRecord.id}`,
    entryCount: entries.length,
  });
}

export async function seedDescriptionEntry(input: {
  surreal: Surreal;
  targetRecord: RecordId;
  text: string;
  reasoning: string;
  triggeredBy: RecordId[];
}): Promise<void> {
  const entry: DescriptionEntry = {
    text: input.text,
    reasoning: input.reasoning,
    triggered_by: input.triggeredBy,
    created_at: new Date(),
  };

  await input.surreal.update(input.targetRecord).merge({
    description: input.text,
    description_entries: [entry],
    updated_at: new Date(),
  });

  logInfo("description.seed.success", "Description seeded", {
    targetRecord: `${input.targetRecord.table}:${input.targetRecord.id}`,
  });
}
import type { RecordId, Surreal } from "surrealdb";
import { logError, logInfo } from "../http/observability";
import { appendDescriptionEntry } from "./persist";
import type { DescriptionEntry, DescriptionTarget, DescriptionTrigger } from "./types";

type AffectedEntity = {
  id: RecordId;
  type: DescriptionTarget;
};

export async function fireDescriptionUpdates(input: {
  surreal: Surreal;
  extractionModel: any;
  trigger: DescriptionTrigger;
}): Promise<void> {
  const affected = await findAffectedEntities(input.surreal, input.trigger);

  if (affected.length === 0) {
    return;
  }

  logInfo("description.trigger.fire", "Firing description updates", {
    triggerKind: input.trigger.kind,
    triggerEntity: `${input.trigger.entity.table}:${input.trigger.entity.id}`,
    affectedCount: affected.length,
  });

  const entry: DescriptionEntry = {
    text: input.trigger.summary,
    reasoning: input.trigger.kind.replace(/_/g, " "),
    triggered_by: [input.trigger.entity],
    created_at: new Date(),
  };

  const updates = affected.map((target) =>
    appendDescriptionEntry({
      surreal: input.surreal,
      extractionModel: input.extractionModel,
      targetRecord: target.id,
      targetType: target.type,
      entry,
    }).catch((error) => {
      logError("description.trigger.update_failed", "Description update failed for target", error, {
        triggerKind: input.trigger.kind,
        targetRecord: `${target.id.table}:${target.id.id}`,
      });
    }),
  );

  await Promise.all(updates);
}

async function findAffectedEntities(
  surreal: Surreal,
  trigger: DescriptionTrigger,
): Promise<AffectedEntity[]> {
  const table = trigger.entity.table.name;

  if (trigger.kind === "decision_confirmed" && table === "decision") {
    return findEntitiesRelatedToDecision(surreal, trigger.entity);
  }

  if (trigger.kind === "task_completed" && table === "task") {
    return findEntitiesRelatedToTask(surreal, trigger.entity);
  }

  if (trigger.kind === "feature_created" || trigger.kind === "feature_completed") {
    return findEntitiesRelatedToFeature(surreal, trigger.entity);
  }

  return [];
}

async function findEntitiesRelatedToDecision(
  surreal: Surreal,
  decisionRecord: RecordId,
): Promise<AffectedEntity[]> {
  // A decision belongs_to projects and features
  const [rows] = await surreal
    .query<[Array<{ out: RecordId }>]>(
      "SELECT out FROM belongs_to WHERE `in` = $decision;",
      { decision: decisionRecord },
    )
    .collect<[Array<{ out: RecordId }>]>();

  const affected: AffectedEntity[] = [];
  for (const row of rows) {
    const table = row.out.table.name;
    if (table === "project" || table === "feature") {
      affected.push({ id: row.out, type: table });
    }
  }

  // Also find tasks that belong to the same project/feature
  if (affected.length > 0) {
    const parentIds = affected.map((e) => e.id);
    const [taskRows] = await surreal
      .query<[Array<{ in: RecordId }>]>(
        "SELECT `in` FROM belongs_to WHERE out IN $parents AND record::table(`in`) = 'task';",
        { parents: parentIds },
      )
      .collect<[Array<{ in: RecordId }>]>();

    for (const row of taskRows) {
      affected.push({ id: row.in, type: "task" });
    }
  }

  return affected;
}

async function findEntitiesRelatedToTask(
  surreal: Surreal,
  taskRecord: RecordId,
): Promise<AffectedEntity[]> {
  // A task belongs_to features and projects
  const [rows] = await surreal
    .query<[Array<{ out: RecordId }>]>(
      "SELECT out FROM belongs_to WHERE `in` = $task;",
      { task: taskRecord },
    )
